const authors = ["Gradient Field Team", "Mira Lee", "Sara Kim", "Elena Cruz", "Nolan Park"];

const catMeta = {
  planning: { cat: "guide", catLabel: "Planning", tint: "#8a9d5e" },
  family: { cat: "family", catLabel: "Family", tint: "#d7a84f" },
  access: { cat: "access", catLabel: "Access", tint: "#c8643b" },
  terrain: { cat: "data", catLabel: "Terrain", tint: "#4f7f8f" },
  seasonal: { cat: "seasonal", catLabel: "Seasonal", tint: "#9f7651" },
  parks: { cat: "parks", catLabel: "Parks", tint: "#608a70" },
  tools: { cat: "data", catLabel: "Tools", tint: "#4f7f8f" },
  itinerary: { cat: "guide", catLabel: "Itinerary", tint: "#8a9d5e" },
  safety: { cat: "seasonal", catLabel: "Safety", tint: "#9f7651" }
};

function day(index) {
  const base = new Date(Date.UTC(2026, 5, 1));
  base.setUTCDate(base.getUTCDate() - index);
  return base.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric", timeZone: "UTC" });
}

function sentenceList(values) {
  return values.slice(0, -1).join(", ") + (values.length > 1 ? ` and ${values.at(-1)}` : values[0]);
}

function makeSections(seed, cluster) {
  const terms = sentenceList(seed.signals);
  return [
    [`Start with the decision this ${seed.entity} is supposed to support`, [
      `A useful trail article starts with the reader's decision, not with a dramatic description of scenery. In this case, the decision is whether ${seed.situation.toLowerCase()} can choose a route without turning a national park day into a test of endurance, patience or mobility. The route may still be short and scenic, but the plan has to survive arrival timing, group pace, weather and current official conditions.`,
      `Gradient Trail treats ${seed.entity.toLowerCase()} as a planning problem made of separate signals: ${terms}. Looking at those signals separately prevents the common mistake of letting one attractive phrase, such as easy, flat, famous or family-friendly, do work that only a complete route check can do.`
    ]],
    [`Read ${seed.primaryMetric.toLowerCase()} before trusting the headline`, [
      `${seed.primaryMetric} is the first number to slow down and translate. It does not answer the whole question by itself, but it tells you where hidden effort may sit. A route with a modest total distance can still feel demanding if the steep section is near the end, if the surface slows the group down, or if the return leg happens after heat and crowding have built up.`,
      `For this topic, the practical move is to compare ${seed.primaryMetric.toLowerCase()} with at least two other route facts instead of reading it alone. Pair it with ${seed.signals[0].toLowerCase()} and ${seed.signals[1].toLowerCase()}, then ask what would make the same route feel harder for the least flexible person in the group.`
    ]],
    [`Watch the false shortcut: ${seed.avoid.toLowerCase()}`, [
      `The most common planning shortcut here is ${seed.avoid.toLowerCase()}. It feels efficient because it gives a quick answer, but it usually ignores the exact condition that changes the day. A short route can still have poor shade. A paved route can still be too steep. A famous viewpoint can still require a parking or shuttle plan that makes the outing less gentle than expected.`,
      `A better approach is to write down the one thing that would cause you to change plans before you leave. If that condition is unknown, the article has not finished its job. The official park page, current alerts, road status, weather and accessibility notes have to come after the terrain screen and before the final choice.`
    ]],
    [`Use ${seed.reward.toLowerCase()} as the reward test`, [
      `Gentle routes need a reward test because low effort alone is not enough. ${seed.reward} gives the route a reason to exist in the itinerary. It can be a lake edge, a shaded river corridor, a boardwalk through unusual ground, a quieter viewpoint, an interpretive stop or simply a route shape that lets a mixed group move together without pressure.`,
      `When two routes look equally manageable, choose the one with the clearer reward and the lower logistical friction. That is often more valuable than chasing a trail with a better reputation but a worse fit for the day's actual constraints.`
    ]],
    [`Make the final call with a conservative check`, [
      `Before treating the route as ready, run one conservative check: what would make this plan wrong today? The answer may be heat, smoke, snow, a closure, construction, a full parking lot, shuttle changes, wet boardwalk, loose gravel, exposed sun or a mobility detail that the map does not show. If the answer matters, verify it through the park's official information before leaving.`,
      `This is the editorial line Gradient Trail follows across every article. Terrain data can make a shortlist smarter, but current official information controls the actual visit. The right route is the one whose distance, grade, surface, access wording, facilities and current conditions agree with the group you are planning for.`
    ]]
  ];
}

function makeTool(seed) {
  return {
    title: seed.toolTitle,
    intro: `Use this tool before committing to ${seed.entity.toLowerCase()}. It turns the article's main idea into a route-level check you can apply on a park page, map, or Gradient Trail listing.`,
    rows: [
      [seed.signals[0], `What does the route page actually say about ${seed.signals[0].toLowerCase()}?`, `Keep the plan only if this signal matches ${seed.situation.toLowerCase()}.`],
      [seed.signals[1], `Could ${seed.signals[1].toLowerCase()} make the route feel harder than the title suggests?`, "Adjust the route, start time or backup plan before the visit."],
      [seed.signals[2], `Is ${seed.signals[2].toLowerCase()} based on official information, measured terrain or a loose description?`, "Give official and measured evidence more weight than a vague label."],
      ["Current condition", "What current alert, weather or access detail could override the plan?", "Check the official park source close to the visit."]
    ]
  };
}

function makeTakeaways(seed) {
  return [
    `${seed.primaryMetric} should be read with ${seed.signals[0].toLowerCase()} and current conditions, not alone.`,
    `Avoid ${seed.avoid.toLowerCase()} when the group depends on a predictable route.`,
    `${seed.reward} is the reason a gentle route can still feel intentional and memorable.`
  ];
}

function makePost(seed, index) {
  const meta = catMeta[seed.cluster];
  return {
    slug: seed.slug,
    title: seed.title,
    subtitle: seed.subtitle,
    cat: meta.cat,
    catLabel: meta.catLabel,
    tint: meta.tint,
    seed: seed.slug,
    author: authors[index % authors.length],
    date: day(index + 11),
    read: `${9 + (index % 4)} min`,
    featured: false,
    dek: seed.dek,
    readerJob: seed.readerJob,
    structureType: seed.structure,
    decisionTool: makeTool(seed),
    sections: makeSections(seed, meta),
    takeaways: makeTakeaways(seed)
  };
}

