export const expansionPosts = seeds.flatMap(([cluster, rows]) => rows.map((row, localIndex) => {
  const [slug, title, subtitle, entity, situation, primaryMetric, avoid, reward, signals, toolTitle, dek, structure] = row;
  return makePost({
    cluster,
    slug,
    title,
    subtitle,
    entity,
    situation,
    primaryMetric,
    avoid,
    reward,
    signals,
    toolTitle,
    dek,
    readerJob: `${situation} and needs a defensible route decision before visiting.`,
    structure
  }, seeds.slice(0, seeds.findIndex(([key]) => key === cluster)).reduce((sum, [, items]) => sum + items.length, 0) + localIndex);
}));
